import{_ as a,o as i,c as t,a3 as s}from"./chunks/framework.LBeL10WQ.js";const g=JSON.parse('{"title":"Social Ads (publisher)","description":"Monétisez votre audience Instagram et TikTok via les Partnership Ads. Guide complet pour activer le tagging, les droits de boost et déclencher votre rémunération.","frontmatter":{"title":"Social Ads (publisher)","description":"Monétisez votre audience Instagram et TikTok via les Partnership Ads. Guide complet pour activer le tagging, les droits de boost et déclencher votre rémunération.","keywords":["social ads","partnership ads","instagram","tiktok","monétisation audience","retail media"]},"headers":[],"relativePath":"publishers/sponsored-social/index.md","filePath":"publishers/sponsored-social/index.md"}'),r={name:"publishers/sponsored-social/index.md"};function o(n,e,l,u,d,p){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="social-ads-partnership-ads" tabindex="-1">Social Ads (Partnership Ads) <a class="header-anchor" href="#social-ads-partnership-ads" aria-label="Permalink to &quot;Social Ads (Partnership Ads)&quot;">​</a></h1><p>Monétisez votre audience sociale (Instagram, TikTok) sans polluer votre ligne éditoriale grâce aux Partnership Ads.</p><hr><h2 id="le-principe" tabindex="-1">Le principe <a class="header-anchor" href="#le-principe" aria-label="Permalink to &quot;Le principe&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Contrairement à l&#39;influence classique, nous utilisons la <strong>Sponsorisation</strong> :</p><ol><li>Vous créez et publiez un contenu qualitatif (avec mention &quot;Partenariat rémunéré&quot;).</li><li>L&#39;annonceur investit son propre budget média pour diffuser <strong>votre post</strong> auprès de milliers de nouvelles personnes.</li><li>Vous partagez le lien de publication — getinside transmet à l&#39;annonceur pour lancer l&#39;amplification.</li></ol></div><hr><h2 id="vos-avantages" tabindex="-1">Vos avantages <a class="header-anchor" href="#vos-avantages" aria-label="Permalink to &quot;Vos avantages&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>💰 Rémunération</strong><p>Vous êtes rémunéré pour la création du contenu et/ou sa publication. Revenus crédités sur votre Wallet 30 jours après la fin de campagne.</p></div><div class="gi-value-card"><strong>📈 Croissance Gratuite</strong><p>L&#39;annonceur paie pour diffuser <strong>votre profil</strong> à une large audience. Acquisition d&#39;abonnés gratuite sans dépenser votre propre budget.</p></div><div class="gi-value-card"><strong>✨ Qualité Préservée</strong><p>Le post est amplifié depuis votre compte (Dark post ou Boost). Pas besoin de spammer votre feed organique.</p></div></div><hr><h2 id="pourquoi-passer-par-getinside" tabindex="-1">Pourquoi passer par getinside ? <a class="header-anchor" href="#pourquoi-passer-par-getinside" aria-label="Permalink to &quot;Pourquoi passer par getinside ?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>⚙️ Setup Simplifié</strong><p>La configuration des droits publicitaires sur Meta ou TikTok est complexe. Nous vous guidons pas à pas pour activer les autorisations sans erreur.</p></div><div class="gi-value-card"><strong>🤝 Marques Premium</strong><p>Collaborez avec des annonceurs vérifiés qui recherchent de la performance long terme, pas des opérations ponctuelles.</p></div></div><hr><h2 id="guide-de-publication-tagging" tabindex="-1">Guide de Publication &amp; Tagging <a class="header-anchor" href="#guide-de-publication-tagging" aria-label="Permalink to &quot;Guide de Publication &amp; Tagging&quot;">​</a></h2><p>Pour que l&#39;annonceur puisse payer la diffusion, vous devez impérativement activer les options de partenariat lors de la publication.</p><div class="tip custom-block"><p class="custom-block-title">Pourquoi ces étapes sont obligatoires ?</p><p>En cochant &quot;Autoriser le partenaire à booster&quot;, l&#39;annonceur peut diffuser votre contenu comme une publicité depuis son propre compte. Sans cette autorisation, <strong>la campagne ne peut pas démarrer</strong> et <strong>votre rémunération est bloquée</strong>.</p></div><hr><h2 id="instagram-—-partnership-ads" tabindex="-1">Instagram — Partnership Ads <a class="header-anchor" href="#instagram-—-partnership-ads" aria-label="Permalink to &quot;Instagram — Partnership Ads&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Préparer le post</h3><p>Créez votre Post ou Reel normalement. Arrivez à l&#39;étape finale (juste avant de cliquer sur &quot;Partager&quot;).</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Paramètres Avancés</h3><p>Descendez tout en bas et cliquez sur <strong>&quot;Paramètres avancés&quot;</strong>.</p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Ajouter le label + identifier la marque</h3><p>Activez <strong>&quot;Ajouter un label Partenariat rémunéré&quot;</strong>, puis cliquez sur <strong>&quot;Ajouter des partenaires de marque&quot;</strong> et recherchez le compte de l&#39;annonceur (indiqué dans le brief).</p></div></div><div class="gi-step"><div class="gi-step-num">4</div><div class="gi-step-body"><h3>Autoriser le boost — Étape critique</h3><p>Activez l&#39;option <strong>&quot;Autoriser le partenaire de marque à booster&quot;</strong> (Allow brand partner to boost).</p></div></div><div class="danger custom-block"><p class="custom-block-title">Autorisation de boost obligatoire (Instagram)</p><p>Sans cette case cochée, l&#39;annonceur ne peut pas lancer la campagne média et votre rémunération est bloquée.</p><p>En cas de problème après publication : retournez sur le post → 3 points (…) → &quot;Modifier&quot; → vérifiez les deux options.</p></div><hr><h2 id="tiktok-—-spark-ads" tabindex="-1">TikTok — Spark Ads <a class="header-anchor" href="#tiktok-—-spark-ads" aria-label="Permalink to &quot;TikTok — Spark Ads&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Accéder aux paramètres de publicité</h3><p>Publiez la vidéo. Allez dessus → cliquez sur les <strong>3 points (...)</strong> en bas à droite → faites défiler jusqu&#39;à <strong>&quot;Paramètres de publicité&quot;</strong> (Ad settings).</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Activer l&#39;autorisation</h3><p>Activez l&#39;option <strong>&quot;Autorisation de publicité&quot;</strong> (Ad authorization).</p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Générer et transmettre le code</h3><p>Cliquez sur <strong>&quot;Générer un code&quot;</strong>, choisissez une durée (30 ou 60 jours), copiez le code et collez-le dans la messagerie de la campagne sur <a href="https://app.getinside.media/" target="_blank">app.getinside.media</a>.</p></div></div><hr><h2 id="checklist-avant-publication" tabindex="-1">Checklist avant publication <a class="header-anchor" href="#checklist-avant-publication" aria-label="Permalink to &quot;Checklist avant publication&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Vérifiez chaque point avant de publier</p><ul><li><strong>Instagram :</strong> Label &quot;Partenariat rémunéré&quot; activé + compte annonceur identifié + <strong>&quot;Autoriser le partenaire à booster&quot;</strong> coché</li><li><strong>TikTok :</strong> &quot;Autorisation de publicité&quot; activée + code généré et transmis via la messagerie plateforme</li><li><strong>Les deux :</strong> Après publication, confirmez la diffusion sur <a href="https://app.getinside.media/" target="_blank" rel="noreferrer">app.getinside.media</a> pour déclencher le paiement</li></ul></div><hr><h2 id="bonnes-pratiques-editoriales" tabindex="-1">Bonnes pratiques éditoriales <a class="header-anchor" href="#bonnes-pratiques-editoriales" aria-label="Permalink to &quot;Bonnes pratiques éditoriales&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>🎯 Authenticité</strong><p>Utilisez votre ton habituel. Ne jouez pas un rôle — c&#39;est précisément ce que l&#39;annonceur recherche chez vous.</p></div><div class="gi-value-card"><strong>⚖️ Transparence</strong><p>Le label &quot;Partenariat rémunéré&quot; est ajouté automatiquement, vous assurant la conformité avec la réglementation française sur la publicité.</p></div><div class="gi-value-card"><strong>📊 Performance</strong><p>Partagez le lien de votre publication avec votre gestionnaire de campagne getinside pour le suivi des performances et l&#39;optimisation.</p></div></div>',33)])])}const v=a(r,[["render",o]]);export{g as __pageData,v as default};
